INSERT INTO `book` VALUES
(1, 'Software Engineering with Python', 'Packt Publishing', 'A comprehensive guide to software engineering concepts using Python, covering project structure, clean coding practices, testing methodologies, software design principles, and real-world development workflows for building maintainable applications.', 3, 2, 'Backend', '/images/download1.png'),
(2, 'Advanced Programming by Example', 'John W. Perry', 'An in-depth programming resource that teaches advanced development techniques through practical examples, including algorithms, object-oriented design, debugging strategies, performance optimization, and modern software development practices.', 2, 2, 'Backend', '/images/download2.png'),
(3, 'Kotlin Programming by Example', 'Iyanu Adelekan', 'Learn Kotlin through hands-on projects and real-world applications while exploring Android development, web services, object-oriented programming, functional concepts, and best practices for building scalable software solutions.', 4, 3, 'Frontend', '/images/download3.png'),
(4, 'Linux Programming by Example', 'Arnold Robbins', 'A practical introduction to Linux programming that covers system commands, shell scripting, process management, file systems, networking concepts, and development techniques commonly used in Linux environments.', 3, 2, 'DevOps', '/images/download5.png'),
(5, 'R Programming by Example', 'Omar Trejo Navarro', 'A beginner-friendly guide to R programming featuring practical projects, data manipulation techniques, statistical analysis methods, visualization tools, and step-by-step exercises for data-driven problem solving.', 2, 1, 'Data', '/images/download.png'),
(6, 'Python Programming with Raspberry Pi', 'Sai Yamanoor & Srihari Yamanoor', 'Build creative hardware and software projects using Python and Raspberry Pi, including robotics, sensors, automation systems, electronics integration, and real-world engineering applications.', 3, 2, 'DevOps', '/images/downloadd.png'),
(7, 'COM Programming by Example', 'John E. Swanke', 'A detailed guide to COM development covering MFC, ATL, ADO, component-based software architecture, Windows integration techniques, and enterprise application development through practical examples.', 2, 2, 'Backend', '/images/download4.png'),
(8, 'Practical Programming', 'Multiple Authors', 'A broad programming reference packed with thousands of code examples across multiple topics, helping developers strengthen problem-solving skills, understand programming concepts, and improve coding proficiency.', 5, 4, 'Backend', '/images/downloadf.png');